using Store;

namespace Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // --- AddItem ---

    [TestMethod]
    [DataRow("SKU-1", 2, 9.99)]
    [DataRow("SKU-2", 1, 0.01)]
    [DataRow("SKU-3", 100, 49.99)]
    public void AddItem_ValidInputs_IncludedInTotal(string sku, int qty, double price)
    {
        _cart.AddItem(sku, qty, (decimal)price);

        Assert.AreEqual((decimal)(qty * price), _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        _cart.AddItem("A", 2, 10m);
        _cart.AddItem("A", 3, 10m);

        Assert.AreEqual(50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Allowed()
    {
        _cart.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 5m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _cart.AddItem("X", qty, 5m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _cart.AddItem("X", 1, -1m));
    }

    // --- RemoveItem ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovedFromTotal()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 1, 20m);

        _cart.RemoveItem("A");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(() => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    // --- CalculateTotal ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsCorrectly()
    {
        _cart.AddItem("A", 2, 5m);
        _cart.AddItem("B", 3, 10m);

        Assert.AreEqual(40m, _cart.CalculateTotal());
    }

    // --- ApplyCoupon ---

    [TestMethod]
    [DataRow("SAVE10", 90.0)]
    [DataRow("SAVE20", 80.0)]
    [DataRow("HALF", 50.0)]
    public void ApplyCoupon_ValidCode_DiscountsTotal(string code, double expectedTotal)
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon(code);

        Assert.AreEqual((decimal)expectedTotal, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmpty_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedBeforeAddingItems_StillDiscounts()
    {
        _cart.ApplyCoupon("SAVE10");
        _cart.AddItem("A", 1, 50m);

        Assert.AreEqual(45m, _cart.CalculateTotal());
    }
}

